	test('shouldAutoClosePair with overlapping pairs', () => {
		// Test for conflicting pairs: '(' closes with ')' and '(*' closes with '*)'
		let sup = new CharacterPairSupport({
			autoClosingPairs: [
				{ open: '(', close: ')' },
				{ open: '(*', close: '*)', notIn: ['string'] }
			]
		});
		// When we see '(', it should auto-close with ')'
		assert.equal(testShouldAutoClose(sup, [], '(', 1), true);
		// When we see '*' after '(', it should recognize the '(*' pair
		assert.equal(testShouldAutoClose(sup, [], '*', 1), false); // '*' alone is not a pair
		assert.equal(testShouldAutoClose(sup, [], '(', 2), true);  // The '(' pair can still match
	});

});

