	test('issue #7100: Mouse word selection is strange when non-word character is at the end of line', () => {
		let model = createTextModel(
			[
				'before.a',
				'before',
				'hello:',
				'there:',
				'this is strange:',
				'here',
				'it',
				'is',
			].join('\n')
		);

		withTestCodeEditor(null, { model: model }, (editor, viewModel) => {
			CoreNavigationCommands.WordSelect.runEditorCommand(null, editor, {
				position: new Position(3, 7)
			});
			assertCursor(viewModel, new Selection(3, 7, 3, 7));

			CoreNavigationCommands.WordSelectDrag.runEditorCommand(null, editor, {
				position: new Position(4, 7)
			});
			assertCursor(viewModel, new Selection(3, 7, 4, 7));
		});
	});

	test('Conflicting auto-closing pairs: (* and ()', () => {
		// Test for issue where having both '(' -> ')' and '(*' -> '*)' pairs
		// would result in '(**))' instead of '(*)'
		const languageId = new LanguageIdentifier('conflictingPairsMode', 6);
		class ConflictingPairsMode extends MockMode {
			constructor() {
				super(languageId);
				this._register(LanguageConfigurationRegistry.register(this.getLanguageIdentifier(), {
					autoClosingPairs: [
						{ open: '(', close: ')' },
						{ open: '(*', close: '*)', notIn: ['string'] }
					],
				}));
			}
		}

		let mode = new ConflictingPairsMode();
		let model = createTextModel(
			[''],
			TextModel.DEFAULT_CREATION_OPTIONS,
			mode.getLanguageIdentifier()
		);

		withTestCodeEditor(null, { model: model }, (editor, viewModel) => {
			// Type '(' should result in '()'
			viewModel.type('(', 'keyboard');
			assert.strictEqual(model.getLineContent(1), '()', 'After typing "("');

			// Type '*' should result in '(*)' not '(**)'
			viewModel.type('*', 'keyboard');
			assert.strictEqual(model.getLineContent(1), '(*)', 'After typing "(*", should get "(*)" not "(**)"');
		});

		model.dispose();
		mode.dispose();
	});
});

