   261→	public static replacePreviousChar(prevEditOperationType: EditOperationType, config: CursorConfiguration, model: ITextModel, selections: Selection[], txt: string, replaceCharCnt: number): EditOperationResult {
   262→		let commands: Array<ICommand | null> = [];
   263→		for (let i = 0, len = selections.length; i < len; i++) {
   264→			const selection = selections[i];
   265→			if (!selection.isEmpty()) {
   266→				// looks like https://github.com/microsoft/vscode/issues/2773
   267→				// where a cursor operation occurred before a canceled composition
   268→				// => ignore composition
   269→				commands[i] = null;
   270→				continue;
   271→			}
   272→			const pos = selection.getPosition();
   273→			const startColumn = Math.max(1, pos.column - replaceCharCnt);
   274→			const range = new Range(pos.lineNumber, startColumn, pos.lineNumber, pos.column);
   275→			const oldText = model.getValueInRange(range);
   276→			if (oldText === txt) {
   277→				// => ignore composition that doesn't do anything
   278→				commands[i] = null;
   279→				continue;
   280→			}
   281→			commands[i] = new ReplaceCommand(range, txt);
   282→		}
   283→		return new EditOperationResult(EditOperationType.Typing, commands, {
   284→			shouldPushStackElementBefore: (prevEditOperationType !== EditOperationType.Typing),
   285→			shouldPushStackElementAfter: false
   286→		});
   287→	}
