   297→	private static _enter(config: CursorConfiguration, model: ITextModel, keepPosition: boolean, range: Range): ICommand {
   298→		if (config.autoIndent === EditorAutoIndentStrategy.None) {
   299→			return TypeOperations._typeCommand(range, '\n', keepPosition);
   300→		}
   301→		if (!model.isCheapToTokenize(range.getStartPosition().lineNumber) || config.autoIndent === EditorAutoIndentStrategy.Keep) {
   302→			let lineText = model.getLineContent(range.startLineNumber);
   303→			let indentation = strings.getLeadingWhitespace(lineText).substring(0, range.startColumn - 1);
   304→			return TypeOperations._typeCommand(range, '\n' + config.normalizeIndentation(indentation), keepPosition);
   305→		}
   306→
   307→		const r = LanguageConfigurationRegistry.getEnterAction(config.autoIndent, model, range);
   308→		if (r) {
   309→			if (r.indentAction === IndentAction.None) {
   310→				// Nothing special
   311→				return TypeOperations._typeCommand(range, '\n' + config.normalizeIndentation(r.indentation + r.appendText), keepPosition);
   312→
   313→			} else if (r.indentAction === IndentAction.Indent) {
   314→				// Indent once
   315→				return TypeOperations._typeCommand(range, '\n' + config.normalizeIndentation(r.indentation + r.appendText), keepPosition);
   316→
   317→			} else if (r.indentAction === IndentAction.IndentOutdent) {
   318→				// Ultra special
   319→				const normalIndent = config.normalizeIndentation(r.indentation);
   320→				const increasedIndent = config.normalizeIndentation(r.indentation + r.appendText);
   321→
   322→				const typeText = '\n' + increasedIndent + '\n' + normalIndent;
   323→
   324→				if (keepPosition) {
   325→					return new ReplaceCommandWithoutChangingPosition(range, typeText, true);
   326→				} else {
   327→					return new ReplaceCommandWithOffsetCursorState(range, typeText, -1, increasedIndent.length - normalIndent.length, true);
   328→				}
   329→			} else if (r.indentAction === IndentAction.Outdent) {
   330→				const actualIndentation = TypeOperations.unshiftIndent(config, r.indentation);
   331→				return TypeOperations._typeCommand(range, '\n' + config.normalizeIndentation(actualIndentation + r.appendText), keepPosition);
   332→			}
   333→		}
   334→
   335→		const lineText = model.getLineContent(range.startLineNumber);
   336→		const indentation = strings.getLeadingWhitespace(lineText).substring(0, range.startColumn - 1);
   337→
   338→		if (config.autoIndent >= EditorAutoIndentStrategy.Full) {
   339→			const ir = LanguageConfigurationRegistry.getIndentForEnter(config.autoIndent, model, range, {
   340→				unshiftIndent: (indent) => {
   341→					return TypeOperations.unshiftIndent(config, indent);
   342→				},
   343→				shiftIndent: (indent) => {
   344→					return TypeOperations.shiftIndent(config, indent);
   345→				},
   346→				normalizeIndentation: (indent) => {
   347→					return config.normalizeIndentation(indent);
   348→				}
   349→			});
   350→
   351→			if (ir) {
   352→				let oldEndViewColumn = CursorColumns.visibleColumnFromColumn2(config, model, range.getEndPosition());
   353→				const oldEndColumn = range.endColumn;
   354→
   355→				let beforeText = '\n';
   356→				if (indentation !== config.normalizeIndentation(ir.beforeEnter)) {
   357→					beforeText = config.normalizeIndentation(ir.beforeEnter) + lineText.substring(indentation.length, range.startColumn - 1) + '\n';
   358→					range = new Range(range.startLineNumber, 1, range.endLineNumber, range.endColumn);
   359→				}
   360→
   361→				const newLineContent = model.getLineContent(range.endLineNumber);
   362→				const firstNonWhitespace = strings.firstNonWhitespaceIndex(newLineContent);
   363→				if (firstNonWhitespace >= 0) {
   364→					range = range.setEndPosition(range.endLineNumber, Math.max(range.endColumn, firstNonWhitespace + 1));
   365→				} else {
   366→					range = range.setEndPosition(range.endLineNumber, model.getLineMaxColumn(range.endLineNumber));
   367→				}
   368→
   369→				if (keepPosition) {
   370→					return new ReplaceCommandWithoutChangingPosition(range, beforeText + config.normalizeIndentation(ir.afterEnter), true);
   371→				} else {
   372→					let offset = 0;
   373→					if (oldEndColumn <= firstNonWhitespace + 1) {
   374→						if (!config.insertSpaces) {
   375→							oldEndViewColumn = Math.ceil(oldEndViewColumn / config.indentSize);
   376→						}
   377→						offset = Math.min(oldEndViewColumn + 1 - config.normalizeIndentation(ir.afterEnter).length - 1, 0);
   378→					}
   379→					return new ReplaceCommandWithOffsetCursorState(range, beforeText + config.normalizeIndentation(ir.afterEnter), 0, offset, true);
   380→				}
   381→			}
   382→		}
   383→
   384→		return TypeOperations._typeCommand(range, '\n' + config.normalizeIndentation(indentation), keepPosition);
   385→	}
