   387→	private static _isAutoIndentType(config: CursorConfiguration, model: ITextModel, selections: Selection[]): boolean {
   388→		if (config.autoIndent < EditorAutoIndentStrategy.Full) {
   389→			return false;
   390→		}
   391→
   392→		for (let i = 0, len = selections.length; i < len; i++) {
   393→			if (!model.isCheapToTokenize(selections[i].getEndPosition().lineNumber)) {
   394→				return false;
   395→			}
   396→		}
   397→
   398→		return true;
