   401→	private static _runAutoIndentType(config: CursorConfiguration, model: ITextModel, range: Range, ch: string): ICommand | null {
   402→		const currentIndentation = LanguageConfigurationRegistry.getIndentationAtPosition(model, range.startLineNumber, range.startColumn);
   403→		const actualIndentation = LanguageConfigurationRegistry.getIndentActionForType(config.autoIndent, model, range, ch, {
   404→			shiftIndent: (indentation) => {
   405→				return TypeOperations.shiftIndent(config, indentation);
   406→			},
   407→			unshiftIndent: (indentation) => {
   408→				return TypeOperations.unshiftIndent(config, indentation);
   409→			},
   410→		});
   411→
   412→		if (actualIndentation === null) {
   413→			return null;
   414→		}
   415→
   416→		if (actualIndentation !== config.normalizeIndentation(currentIndentation)) {
   417→			const firstNonWhitespace = model.getLineFirstNonWhitespaceColumn(range.startLineNumber);
   418→			if (firstNonWhitespace === 0) {
   419→				return TypeOperations._typeCommand(
   420→					new Range(range.startLineNumber, 1, range.endLineNumber, range.endColumn),
   421→					config.normalizeIndentation(actualIndentation) + ch,
   422→					false
   423→				);
   424→			} else {
   425→				return TypeOperations._typeCommand(
   426→					new Range(range.startLineNumber, 1, range.endLineNumber, range.endColumn),
   427→					config.normalizeIndentation(actualIndentation) +
   428→					model.getLineContent(range.startLineNumber).substring(firstNonWhitespace - 1, range.startColumn - 1) + ch,
   429→					false
   430→				);
   431→			}
   432→		}
   433→
   434→		return null;
   435→	}
