   437→	private static _isAutoClosingOvertype(config: CursorConfiguration, model: ITextModel, selections: Selection[], autoClosedCharacters: Range[], ch: string): boolean {
   438→		if (config.autoClosingOvertype === 'never') {
   439→			return false;
   440→		}
   441→
   442→		if (!config.autoClosingPairsClose2.has(ch)) {
   443→			return false;
   444→		}
   445→
   446→		for (let i = 0, len = selections.length; i < len; i++) {
   447→			const selection = selections[i];
   448→
   449→			if (!selection.isEmpty()) {
   450→				return false;
   451→			}
   452→
   453→			const position = selection.getPosition();
   454→			const lineText = model.getLineContent(position.lineNumber);
   455→			const afterCharacter = lineText.charAt(position.column - 1);
   456→
   457→			if (afterCharacter !== ch) {
   458→				return false;
   459→			}
   460→
   461→			// Do not over-type quotes after a backslash
   462→			const chIsQuote = isQuote(ch);
   463→			const beforeCharacter = position.column > 2 ? lineText.charCodeAt(position.column - 2) : CharCode.Null;
   464→			if (beforeCharacter === CharCode.Backslash && chIsQuote) {
   465→				return false;
   466→			}
   467→
   468→			// Must over-type a closing character typed by the editor
   469→			if (config.autoClosingOvertype === 'auto') {
   470→				let found = false;
   471→				for (let j = 0, lenJ = autoClosedCharacters.length; j < lenJ; j++) {
   472→					const autoClosedCharacter = autoClosedCharacters[j];
   473→					if (position.lineNumber === autoClosedCharacter.startLineNumber && position.column === autoClosedCharacter.startColumn) {
   474→						found = true;
   475→						break;
   476→					}
   477→				}
   478→				if (!found) {
   479→					return false;
   480→				}
   481→			}
   482→		}
   483→
   484→		return true;
   485→	}
