   501→	private static _autoClosingPairIsSymmetric(autoClosingPair: StandardAutoClosingPairConditional): boolean {
   502→		const { open, close } = autoClosingPair;
   503→		return (open.indexOf(close) >= 0 || close.indexOf(open) >= 0);
