private static _findAutoClosingPairOpen(config: CursorConfiguration, model: ITextModel, positions: Position[], ch: string): StandardAutoClosingPairConditional | null {
	const autoClosingPairCandidates = config.autoClosingPairsOpen2.get(ch);
	if (!autoClosingPairCandidates) {
		return null;
	}

	// Determine which auto-closing pair it is
	let autoClosingPair: StandardAutoClosingPairConditional | null = null;
	for (const autoClosingPairCandidate of autoClosingPairCandidates) {
		if (autoClosingPair === null || autoClosingPairCandidate.open.length > autoClosingPair.open.length) {
			let candidateIsMatch = true;
			for (const position of positions) {
				const relevantText = model.getValueInRange(new Range(position.lineNumber, position.column - autoClosingPairCandidate.open.length + 1, position.lineNumber, position.column));
				if (relevantText + ch !== autoClosingPairCandidate.open) {
					candidateIsMatch = false;
					break;
				}
			}

			if (candidateIsMatch) {
				autoClosingPair = autoClosingPairCandidate;
			}
		}
	}

	// Check for conflicting pairs - if we matched a multi-character pair that could conflict
	// with a shorter pair that was already auto-closed, we need to handle the conflict
	if (autoClosingPair && autoClosingPair.open.length > 1) {
		for (const position of positions) {
			// Check if there's a shorter pair that could conflict
			const firstCharOfPair = autoClosingPair.open.charAt(0);
			const shortPairCandidates = config.autoClosingPairsOpen2.get(firstCharOfPair);
			if (shortPairCandidates) {
				for (const shortPair of shortPairCandidates) {
					// Look for a shorter pair that starts with the same character
					if (shortPair.open.length < autoClosingPair.open.length &&
						shortPair.open.length === 1) {
						// Check if this shorter pair was already auto-closed by looking at
						// the character after the first character of our longer pair
						const charAfterFirstOfLongerPair = position.column;
						if (charAfterFirstOfLongerPair <= model.getLineMaxColumn(position.lineNumber)) {
							const textAfterCursor = model.getValueInRange(new Range(position.lineNumber, charAfterFirstOfLongerPair, position.lineNumber, charAfterFirstOfLongerPair + 1));
							// If we find the closing character of the shorter pair immediately after,
							// we have a conflict that will be handled in the insertion logic
							if (textAfterCursor === shortPair.close) {
								// We'll handle this in _runAutoClosingOpenCharType by deleting the conflicting close
								return autoClosingPair;
							}
						}
					}
				}
			}
		}
	}

	return autoClosingPair;
}

