private static _runAutoClosingOpenCharType(prevEditOperationType: EditOperationType, config: CursorConfiguration, model: ITextModel, selections: Selection[], ch: string, insertOpenCharacter: boolean, autoClosingPair: StandardAutoClosingPairConditional): EditOperationResult {
	let commands: ICommand[] = [];
	for (let i = 0, len = selections.length; i < len; i++) {
		const selection = selections[i];
		const position = selection.getPosition();

		// Check for conflicting closing pairs when we have a multi-character pair
		// that overlaps with previously auto-closed pairs
		if (autoClosingPair.open.length > 1 && insertOpenCharacter) {
			// Look for a closing character right after the current position that might conflict
			const lineText = model.getLineContent(position.lineNumber);
			// Check the character immediately after the cursor (convert from 1-based to 0-based)
			const charAfter = position.column <= lineText.length ? lineText.charAt(position.column) : '';

			// Check if the character after the cursor is a closing character from a shorter pair
			const closingPairCandidates = config.autoClosingPairsClose2.get(charAfter);
			if (closingPairCandidates && closingPairCandidates.length > 0) {
				// Check if any of these pairs could conflict with our opening pair
				for (const closingPair of closingPairCandidates) {
					// If the first character of our longer pair matches the opening of this closing pair,
					// and the closing character of this pair is what we see after the cursor,
					// then we have a conflict - delete the conflicting closing character
					if (closingPair.open === autoClosingPair.open.charAt(0) && closingPair.close === charAfter) {
						// Create a range that includes the conflicting closing character
						const rangeWithConflict = new Range(
							position.lineNumber,
							position.column,
							position.lineNumber,
							position.column + 1
						);
						const command = new TypeWithAutoClosingCommand(new Selection(rangeWithConflict.startLineNumber, rangeWithConflict.startColumn, rangeWithConflict.endLineNumber, rangeWithConflict.endColumn), ch, insertOpenCharacter, autoClosingPair.close);
						commands[i] = command;
						continue;
					}
				}
			}
		}

		// Default case: create the normal command
		if (!commands[i]) {
			commands[i] = new TypeWithAutoClosingCommand(selection, ch, insertOpenCharacter, autoClosingPair.close);
		}
	}
	return new EditOperationResult(EditOperationType.Typing, commands, {
		shouldPushStackElementBefore: true,
		shouldPushStackElementAfter: false
	});
}

